// Drawing ======================================================================
var drawnItems = new L.FeatureGroup().addTo(map);

const drawControl = new L.Control.Draw({
    draw: {
        polyline : false,
        polygon  : true,
        rectangle: false,
        circle   : false,
        marker   : false,
        circlemarker   : false,
    },
    edit: {
      featureGroup: drawnItems
    }
});
//map.addControl(drawControl);  // ADD back for polygon drawing

L.Rectangle.include({
    contains: function (latLng) {
        return this.getBounds().contains(latLng);
    }
});

L.Polygon.include({
    contains: function (latLng) {
        //console.log("Inside polygon");
        //console.log(latLng);
        return turf.booleanPointInPolygon(new L.Marker(latLng).toGeoJSON(), this.toGeoJSON());
    } 
});


map.on(L.Draw.Event.CREATED, function (event) {
    var layer = event.layer;
    drawnItems.addLayer(layer);

    let bnds = drawnItems.getLayers()[0];
    console.log(Object.getPrototypeOf(bnds));
    let sids = [];
    Object.values(map._layers).forEach((layer) => {
        if (typeof layer.getLatLng === "function"){
          try{
             if (bnds.contains(layer.getLatLng())) {
                layer.setStyle({color: "red"});
                sids.push(layer.options.assetPath.split("/").filter(s => s.endsWith(".cbor")).map(s => s.replace(".cbor", ""))[0]);
             }
          } catch (e) {
          }
        }
    });
    usids = [...new Set(sids)];
    usids = usids.sort();
    osids = 'IDs:\n'
    for (let i = 0; i < usids.length; i++){
      osids += usids[i]+'\n'
    }
    bnds.bindPopup(osids);
});

map.on(L.Draw.Event.EDITVERTEX, function (event) {
    var layer = event.layer;
    let bnds = drawnItems.getLayers()[0];
    let sids = [];
    Object.values(map._layers).forEach((layer) => {
        if (typeof layer.getLatLng === "function"){
          try{
             if (layer.options.color==="red"){
                layer.setStyle({color: layer.options.fillColor});
             }
          } catch (e) {
          }
        }
    });
    Object.values(map._layers).forEach((layer) => {
        if (typeof layer.getLatLng === "function"){
          try{
             if (bnds.contains(layer.getLatLng())) {
                layer.setStyle({color: "red"});
                sids.push(layer.options.assetPath.split("/").filter(s => s.endsWith(".cbor")).map(s => s.replace(".cbor", ""))[0]);
             }
          } catch (e) {
          }
        }
    });
    usids = [...new Set(sids)];
    usids = usids.sort();
    osids = 'IDs:\n'
    for (let i = 0; i < usids.length; i++){
      osids += usids[i]+'\n'
    }
    bnds.bindPopup(osids);
});


map.on('zoomend', function (event) {
    var layer = event.layer;
    let bnds = drawnItems.getLayers()[0];
    if(bnds!==undefined){
    bnds.bringToFront();
    let sids = [];
    Object.values(map._layers).forEach((layer) => {
        if (typeof layer.getLatLng === "function"){
          try{
             if (bnds.contains(layer.getLatLng())) {
                layer.setStyle({color: "red"});
                sids.push(layer.options.assetPath.split("/").filter(s => s.endsWith(".cbor")).map(s => s.replace(".cbor", ""))[0]);
             }
          } catch (e) {
          }
        }
    });
    usids = [...new Set(sids)];
    usids = usids.sort();
    osids = 'IDs:\n'
    for (let i = 0; i < usids.length; i++){
      osids += usids[i]+'\n'
    }
    bnds.bindPopup(osids);
    }
});


map.on(L.Draw.Event.DELETED, function (event) {
    var layer = event.layer;
    Object.values(map._layers).forEach((layer) => {
        if (typeof layer.getLatLng === "function"){
          try{
             if (layer.options.color==="red"){
                layer.setStyle({color: 'yellow'});
             }
          } catch (e) {
          }
        }
    });
});

