// Map event setup =============================================================
map.on("moveend", updateLocationBar);
map.on("moveend", integerTranslateMapPane);
map.on("zoomend", updateLocationBar);
map.on("zoomend", integerTranslateMapPane);
map.on("mousemove", (event) => {label.update(event.latlng);});
map.on("baselayerchange", (event) => {label.options.title = layer_descriptions[event.name];});
map.on("baselayerchange", (event) => {current_layer = current_layer_names[event.name];});

map.whenReady(function () {
    scale.options.maxWidth = Math.round(map.getSize().x * 0.2);
    label.addTo(map);
});


if (urlParam("layer")!==null) {
  layer = urlParam("layer");
  if(Object.hasOwn(selectable_layers,layer)) {
    map.removeLayer(nircam_rgb)
    map.addLayer(selectable_layers[layer])
    current_layer = layer;
  }
}
// if the wcssession is null add an event listener to pan when ready
if (!wcsSession) {
  window.addEventListener("wcsIsReady", () => {
    console.log("WCS is ready, panning to URL coordinates if present");
    if (urlParam("zoom")==null) {
      console.log('A about to call fit Bounds');
      map.fitBounds(L.latLngBounds([[0, 0], [40600, 33400]]));
    } else {
      console.log('A about to call pan from URL');
      panFromUrl(map);
    }
  });
} else {
  console.log("WCS is ready, panning to URL coordinates if present");
  if (urlParam("zoom")==null) {
    console.log('B about to call fit Bounds');
    map.fitBounds(L.latLngBounds([[0, 0], [40600, 33400]]));
  } else {
    console.log('B about to call pan from URL');
    panFromUrl(map);
  }
}
